```js
(function() {
  const tv = window.ttyview;
  if (!tv || tv.apiVersion !== 1) return;
  tv.contributes.theme({
    id: 'sunset',
    name: 'Sunset',
    vars: {
      '--ttv-bg':       '#1a0f1f',
      '--ttv-fg':       '#f0d8b8',
      '--ttv-bg-elev':  '#2a1a2a',
      '--ttv-bg-elev2': '#3a2a3a',
      '--ttv-border':   '#5a3a4a',
      '--ttv-accent':   '#ffaa5e',
      '--ttv-muted':    '#8a6a7a',
    },
  });
})();
```

The platform writes those custom properties to `:root` when the user activates the theme. That's the whole theme contract.
